import{_ as e,o as t,c as r,a3 as l}from"./chunks/framework.4hqxWaF8.js";const p=JSON.parse('{"title":"关于","description":"","frontmatter":{"title":"关于"},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),o={name:"about.md"};function i(n,a,s,h,u,d){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="关于-ai-创客指南" tabindex="-1">关于 AI 创客指南 <a class="header-anchor" href="#关于-ai-创客指南" aria-label="Permalink to &quot;关于 AI 创客指南&quot;">​</a></h1><h2 id="我是谁" tabindex="-1">我是谁 <a class="header-anchor" href="#我是谁" aria-label="Permalink to &quot;我是谁&quot;">​</a></h2><p>一个在 AI 工具链领域深耕的内容创作者。日常使用 Claude Code、Cursor、HyperFrames 等工具做开发，踩坑无数，总结成文。</p><h2 id="这个网站是什么" tabindex="-1">这个网站是什么 <a class="header-anchor" href="#这个网站是什么" aria-label="Permalink to &quot;这个网站是什么&quot;">​</a></h2><p>中文 AI 工具教程的内容荒地。</p><p>2026 年，AI 编程和 AI 视频领域每天都有新工具、新框架、新范式出现。但中文深度教程极度稀缺——HyperFrames 开源 3 个月，中文系统教程几乎为零；Agent Skills 概念火了半年，除了官方文档，能看的中文内容屈指可数。</p><p>这个网站试图填补这个空缺。每篇文章都是<strong>实战验证过的深度教程</strong>，不是机翻官方文档，不是泛泛的介绍文。</p><h2 id="写作原则" tabindex="-1">写作原则 <a class="header-anchor" href="#写作原则" aria-label="Permalink to &quot;写作原则&quot;">​</a></h2><ol><li><strong>只写自己跑通过的工具</strong>：每行代码都亲自执行过</li><li><strong>不只告诉你&quot;怎么做&quot;，更告诉&quot;为什么这样做&quot;</strong>：理解原理比复制粘贴有用</li><li><strong>持续更新</strong>：工具在变，文章也跟着变</li><li><strong>中文优先</strong>：为中文开发者而写，不是翻译英文博客</li></ol><h2 id="内容计划" tabindex="-1">内容计划 <a class="header-anchor" href="#内容计划" aria-label="Permalink to &quot;内容计划&quot;">​</a></h2><ul><li>HyperFrames 系列教程（第一篇已发布）</li><li>Agent Skills 实战系列（第一篇已发布）</li><li>AI 视频工具链对比测评</li><li>工业化视频生产流水线搭建</li><li>Claude Code 深度使用技巧</li></ul><h2 id="支持本站" tabindex="-1">支持本站 <a class="header-anchor" href="#支持本站" aria-label="Permalink to &quot;支持本站&quot;">​</a></h2><p>本站所有文章免费阅读。如果你觉得有收获，可以通过以下方式支持：</p><ul><li><strong>分享文章</strong>给需要的朋友——这是最大的支持</li><li><strong>通过联盟链接购买推荐的工具</strong>——价格不变，本站获得少量佣金</li><li><strong>反馈和建议</strong>——告诉我哪些内容对你有用，哪些还需要补充</li></ul><h2 id="联系我" tabindex="-1">联系我 <a class="header-anchor" href="#联系我" aria-label="Permalink to &quot;联系我&quot;">​</a></h2><ul><li>GitHub：<a href="https://github.com/Lcheng930" target="_blank" rel="noreferrer">github.com/Lcheng930</a></li><li>邮件：通过 GitHub 联系</li></ul><hr><p><em>种一棵内容树，最好的时间是半年前，其次是今天。</em></p>',18)])])}const g=e(o,[["render",i]]);export{p as __pageData,g as default};
